class Animal {
    // speakメソッドの定義
    void speak() {
        System.out.println("...");
    }
}

// Dogクラスの定義
class Dog extends Animal {
    @Override
    // speakメソッドの定義
    void speak() {
        System.out.println("ワンワン");
    }
    void fetch() {
        System.out.println("ボールを取ってきた！");
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Animal a = new Dog();  // アップキャスト（自動）
        a.speak();   // OK → ワンワン（実行時の型Dogのメソッド）
        // a.fetch(); // コンパイルエラー！ Animal型にfetch()はない
    }
}

Animal a = new Dog();  // アップキャスト
Dog d = (Dog) a;       // ダウンキャスト（成功：元々Dogだから）
d.fetch();             // OK → ボールを取ってきた！

Animal a2 = new Cat();
// Dog d2 = (Dog) a2;  // 実行時エラー！ ClassCastException
// a2は実際にはCatのインスタンスなのでDogにキャストできない

Animal a = new Dog();

// 条件分岐
if (a instanceof Dog) {
    Dog d = (Dog) a;  // 安全にダウンキャスト
    d.fetch();
}

if (a instanceof Cat) {
    // ここは実行されない（aはDogなので）
    Cat c = (Cat) a;
}

Animal nullAnimal = null;
System.out.println(nullAnimal instanceof Animal); // false

