// Shapeクラスの定義
class Shape {
    // areaメソッドの定義
    double area() {
        return 0;
    }
}

// Circleクラスの定義
class Circle extends Shape {
    double radius;

    Circle(double radius) {
        this.radius = radius;
    }

    @Override
    // areaメソッドの定義
    double area() {
        return Math.PI * radius * radius;
    }

    // @Override
    // double Area() { }  // コンパイルエラー！ 親クラスにArea()がない
}

// Parentクラスの定義
class Parent {
    // 変数の宣言と初期化
    String name = "親";
    // greetメソッドの定義
    void greet() {
        System.out.println("こんにちは、" + name);
    }
}

// Childクラスの定義
class Child extends Parent {
    String name = "子";
    @Override
    // greetメソッドの定義
    void greet() {
        System.out.println("やあ、" + name);
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Parent p = new Child();
        System.out.println(p.name);  // 親（フィールドは静的束縛）
        p.greet();                   // やあ、子（メソッドは動的束縛）
    }
}

