// Animalクラスの定義
class Animal {
    String name;
    Animal(String name) { this.name = name; }
    // speakメソッドの定義
    void speak() { System.out.println(name + ": ..."); }
}

// Dogクラスの定義
class Dog extends Animal {
    Dog(String name) { super(name); }
    @Override
    // speakメソッドの定義
    void speak() { System.out.println(name + ": ワンワン"); }
}

// Catクラスの定義
class Cat extends Animal {
    Cat(String name) { super(name); }
    @Override
    void speak() { System.out.println(name + ": ニャー"); }
}

// Birdクラスの定義
class Bird extends Animal {
    Bird(String name) { super(name); }
    @Override
    void speak() { System.out.println(name + ": チュンチュン"); }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Animal[] animals = {
            new Dog("ポチ"),
            new Cat("タマ"),
            new Bird("ピッピ")
        };
        // 拡張for文（コレクションの全要素を順番に処理）
        for (Animal a : animals) {
            a.speak();  // 各オブジェクトの型に応じたspeak()が呼ばれる
        }
    }
}
// 出力:
// ポチ: ワンワン
// タマ: ニャー
// ピッピ: チュンチュン

// Printerクラスの定義
class Printer {
    // Animal型の引数 → Dog、Cat、Bird何でも受け取れる
    // printAnimalSoundメソッドの定義
    static void printAnimalSound(Animal animal) {
        System.out.print(animal.name + "の鳴き声: ");
        animal.speak();
    }

    // mainメソッドの定義
    public static void main(String[] args) {
        printAnimalSound(new Dog("ポチ"));   // ポチの鳴き声: ポチ: ワンワン
        printAnimalSound(new Cat("タマ"));   // タマの鳴き声: タマ: ニャー
        printAnimalSound(new Bird("ピッピ")); // ピッピの鳴き声: ピッピ: チュンチュン
    }
}

