// Paymentインターフェースの定義
interface Payment {
    void pay(int amount);
}

// CreditCardクラスの定義
class CreditCard implements Payment {
    @Override
    // payメソッドの定義
    public void pay(int amount) {
        System.out.println("クレジットカードで" + amount + "円支払い");
    }
}

// BankTransferクラスの定義
class BankTransfer implements Payment {
    @Override
    // payメソッドの定義
    public void pay(int amount) {
        System.out.println("銀行振込で" + amount + "円支払い");
    }
}

// EMoneyクラスの定義
class EMoney implements Payment {
    @Override
    public void pay(int amount) {
        System.out.println("電子マネーで" + amount + "円支払い");
    }
}

// Shopクラスの定義
public class Shop {
    static void checkout(Payment payment, int amount) {
        payment.pay(amount);  // どの支払い方法でも同じ呼び出し
    }

    public static void main(String[] args) {
        checkout(new CreditCard(), 5000);
        checkout(new BankTransfer(), 3000);
        checkout(new EMoney(), 1000);
    }
}

// Employeeクラスの定義
abstract class Employee {
    String name;
    int baseSalary;

    Employee(String name, int baseSalary) {
        this.name = name;
        this.baseSalary = baseSalary;
    }
    abstract int calculateBonus();  // サブクラスで実装

    // totalSalaryメソッドの定義
    int totalSalary() {
        return baseSalary + calculateBonus();  // 共通処理
    }
}

// Managerクラスの定義
class Manager extends Employee {
    Manager(String name) { super(name, 500000); }
    @Override
    // calculateBonusメソッドの定義
    int calculateBonus() { return 200000; }
}

// Engineerクラスの定義
class Engineer extends Employee {
    Engineer(String name) { super(name, 400000); }
    @Override
    int calculateBonus() { return 100000; }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Employee[] staff = { new Manager("田中"), new Engineer("鈴木") };
        // 拡張for文（コレクションの全要素を順番に処理）
        for (Employee e : staff) {
            System.out.println(e.name + ": " + e.totalSalary() + "円");
        }
    }
}
// 出力:
// 田中: 700000円
// 鈴木: 500000円

